class EchoingStdin:
    def __init__(self, input: t.BinaryIO, output: t.BinaryIO) -> None:
        """Wrap a binary input stream and echo what is read to an output stream.

        The wrapper proxies most methods to the underlying input stream while
        optionally writing any bytes read to the provided output stream.
        """
        self._input = input
        self._output = output
        self._paused = False

    def __getattr__(self, x: str) -> t.Any:
        """Proxy attribute access to the underlying input stream."""
        return getattr(self._input, x)

    def _echo(self, rv: bytes) -> bytes:
        """Echo bytes to the configured output stream unless paused.

        Returns the bytes unchanged.
        """
        if not self._paused:
            self._output.write(rv)

        return rv

    def read(self, n: int = -1) -> bytes:
        """Read bytes from the underlying stream and echo them."""
        return self._echo(self._input.read(n))

    def read1(self, n: int = -1) -> bytes:
        """Read up to n bytes with a single read from the underlying stream and echo them."""
        return self._echo(self._input.read1(n))  # type: ignore

    def readline(self, n: int = -1) -> bytes:
        """Read a single line from the underlying stream and echo it."""
        return self._echo(self._input.readline(n))

    def readlines(self) -> list[bytes]:
        """Read all lines from the underlying stream and echo each one."""
        return [self._echo(x) for x in self._input.readlines()]

    def __iter__(self) -> cabc.Iterator[bytes]:
        """Iterate over lines/blocks from the underlying stream, echoing each."""
        return iter(self._echo(x) for x in self._input)

    def __repr__(self) -> str:
        """Return the representation of the underlying input stream."""
        return repr(self._input)


@contextlib.contextmanager
def _pause_echo(stream: EchoingStdin | None) -> cabc.Iterator[None]:
    """Context manager to temporarily pause echoing on an EchoingStdin.

    If stream is None this is a no-op context manager.
    """
    if stream is None:
        yield
    else:
        stream._paused = True
        yield
        stream._paused = False


class BytesIOCopy(io.BytesIO):
    """Patch ``io.BytesIO`` to let the written stream be copied to another.

    .. versionadded:: 8.2
    """

    def __init__(self, copy_to: io.BytesIO) -> None:
        """Create a BytesIO that also writes a copy of data into copy_to."""
        super().__init__()
        self.copy_to = copy_to

    def flush(self) -> None:
        """Flush both this buffer and the copy target buffer."""
        super().flush()
        self.copy_to.flush()

    def write(self, b: ReadableBuffer) -> int:
        """Write bytes to both this buffer and the copy target."""
        self.copy_to.write(b)
        return super().write(b)


class StreamMixer:
    """Mixes `<stdout>` and `<stderr>` streams.

    The result is available in the ``output`` attribute.

    .. versionadded:: 8.2
    """

    def __init__(self) -> None:
        """Initialize the mixer with separate stdout/stderr that both copy to output."""
        self.output: io.BytesIO = io.BytesIO()
        self.stdout: io.BytesIO = BytesIOCopy(copy_to=self.output)
        self.stderr: io.BytesIO = BytesIOCopy(copy_to=self.output)

    def __del__(self) -> None:
        """
        Guarantee that embedded file-like objects are closed in a
        predictable order, protecting against races between
        self.output being closed and other streams being flushed on close

        .. versionadded:: 8.2.2
        """
        self.stderr.close()
        self.stdout.close()
        self.output.close()


class _NamedTextIOWrapper(io.TextIOWrapper):
    def __init__(
        self, buffer: t.BinaryIO, name: str, mode: str, **kwargs: t.Any
    ) -> None:
        """Wrap a binary buffer with a text wrapper that has custom name and mode."""
        super().__init__(buffer, **kwargs)
        self._name = name
        self._mode = mode

    @property
    def name(self) -> str:
        """Return the synthetic name of the stream."""
        return self._name

    @property
    def mode(self) -> str:
        """Return the synthetic mode of the stream."""
        return self._mode


def make_input_stream(
    input: str | bytes | t.IO[t.Any] | None, charset: str
) -> t.BinaryIO:
    """Return a binary input stream for the given input value.

    The input can be an existing stream, bytes, str, or None. Strings are
    encoded using the provided charset. If a stream is passed, attempt to
    obtain a binary reader for it.
    """
    # Is already an input stream.
    if hasattr(input, "read"):
        rv = _find_binary_reader(t.cast("t.IO[t.Any]", input))

        if rv is not None:
            return rv

        raise TypeError("Could not find binary reader for input stream.")

    if input is None:
        input = b""
    elif isinstance(input, str):
        input = input.encode(charset)

    return io.BytesIO(input)